const body = $('Set Config').first().json.body || {};
const calendarName = body.calendar || 'personal';
const nextcloudUrl = 'https://cloud.tal.ahmed-rezk.com';
const nextcloudUser = 'admin';

const startDate = body.startDate || '2025-01-01';
const endDate = body.endDate || '2026-12-31';
const formatICalDate = (d) => new Date(d).toISOString().replace(/[-:]/g, '').replace(/\.\d{3}/, '');

const reportXml = `<?xml version="1.0" encoding="utf-8" ?>
<c:calendar-query xmlns:d="DAV:" xmlns:c="urn:ietf:params:xml:ns:caldav">
  <d:prop>
    <d:getetag/>
    <c:calendar-data/>
  </d:prop>
  <c:filter>
    <c:comp-filter name="VCALENDAR">
      <c:comp-filter name="VEVENT">
        <c:time-range start="${formatICalDate(startDate)}" end="${formatICalDate(endDate)}"/>
      </c:comp-filter>
    </c:comp-filter>
  </c:filter>
</c:calendar-query>`;

const url = `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}/`;
const auth = Buffer.from(`${nextcloudUser}:4EMsB-kQLNn-YdnCC-9Dd6Z-GA9jj`).toString('base64');

try {
  const response = await fetch(url, {
    method: 'REPORT',
    headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'application/xml', 'Depth': '1' },
    body: reportXml
  });
  const xml = await response.text();
  const events = [];
  const calDataMatches = xml.match(/<cal:calendar-data[^>]*>([\s\S]*?)<\/cal:calendar-data>/gi) || [];

  for (const calDataMatch of calDataMatches) {
    const calData = calDataMatch.replace(/<[^>]*>/g, '');
    const veventMatch = calData.match(/BEGIN:VEVENT([\s\S]*?)END:VEVENT/);
    if (!veventMatch) continue;
    const vevent = veventMatch[0];
    const extract = (tag) => { const m = vevent.match(new RegExp(`${tag}:(.*)`, 'i')); return m ? m[1].trim() : null; };
    const dtstart = extract('DTSTART');
    const isAllDay = dtstart && !dtstart.includes('T');
    const parseICalDate = (d) => { if (!d) return null; d = d.replace(/Z$/, ''); if (d.length === 8) return `${d.substring(0,4)}-${d.substring(4,6)}-${d.substring(6,8)}`; return `${d.substring(0,4)}-${d.substring(4,6)}-${d.substring(6,8)}T${d.substring(9,11)}:${d.substring(11,13)}:${d.substring(13,15)}Z`; };
    events.push({ uid: extract('UID') || 'unknown', title: extract('SUMMARY') || 'Untitled', description: extract('DESCRIPTION'), start: parseICalDate(dtstart), end: parseICalDate(extract('DTEND')), allDay: isAllDay, location: extract('LOCATION'), status: extract('STATUS') || 'CONFIRMED', priority: extract('PRIORITY') ? parseInt(extract('PRIORITY')) : null, categories: extract('CATEGORIES') ? extract('CATEGORIES').split(',').map(c => c.trim()) : [], recurrence: extract('RRULE'), calendar: calendarName });
  }
  return [{ json: { success: true, events, count: events.length } }];
} catch (error) {
  return [{ json: { success: false, error: error.message } }];
}

const body = $('Set Config').first().json.body;
const eventId = Date.now();
const calendarName = body.calendar || 'personal';

const formatICalDate = (d) => { const pad = (n) => String(n).padStart(2,'0'); return `${d.getUTCFullYear()}${pad(d.getUTCMonth()+1)}${pad(d.getUTCDate())}T${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}${pad(d.getUTCSeconds())}Z`; };
const formatICalDateOnly = (d) => `${d.getUTCFullYear()}${String(d.getUTCMonth()+1).padStart(2,'0')}${String(d.getUTCDate()).padStart(2,'0')}`;
const parseDate = (s) => { if (!s) return null; const d = new Date(s); return isNaN(d.getTime()) ? null : d; };

const now = new Date();
const startDate = parseDate(body.start);
const endDate = parseDate(body.end);
const isAllDay = body.allDay === true;

const lines = ['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//n8n//Nextcloud//EN','CALSCALE:GREGORIAN','BEGIN:VEVENT',`UID:n8n-event-${eventId}`,`DTSTAMP:${formatICalDate(now)}`];
if (body.title) lines.push(`SUMMARY:${body.title}`);
if (startDate) lines.push(isAllDay ? `DTSTART;VALUE=DATE:${formatICalDateOnly(startDate)}` : `DTSTART:${formatICalDate(startDate)}`);
if (endDate) lines.push(isAllDay ? `DTEND;VALUE=DATE:${formatICalDateOnly(endDate)}` : `DTEND:${formatICalDate(endDate)}`);
else if (startDate && !isAllDay) lines.push(`DTEND:${formatICalDate(new Date(startDate.getTime() + 3600000))}`);
if (body.description) lines.push(`DESCRIPTION:${body.description}`);
if (body.location) lines.push(`LOCATION:${body.location}`);
if (body.status) { const m = {'tentative':'TENTATIVE','confirmed':'CONFIRMED','cancelled':'CANCELLED'}; lines.push(`STATUS:${m[body.status]||body.status}`); } else lines.push('STATUS:CONFIRMED');
if (body.transparency) { const m = {'busy':'OPAQUE','free':'TRANSPARENT'}; lines.push(`TRANSP:${m[body.transparency]||body.transparency}`); } else lines.push('TRANSP:OPAQUE');
if (body.priority !== undefined) lines.push(`PRIORITY:${Math.min(9,Math.max(1,parseInt(body.priority)))}`);
if (body.categories) lines.push(`CATEGORIES:${Array.isArray(body.categories)?body.categories.join(','):body.categories}`);
if (body.recurrence) lines.push(`RRULE:${body.recurrence}`);
lines.push('BEGIN:VALARM','ACTION:DISPLAY','DESCRIPTION:Reminder','TRIGGER:-PT15M','END:VALARM','SEQUENCE:0','END:VEVENT','END:VCALENDAR');

const nextcloudUrl = 'https://cloud.tal.ahmed-rezk.com';
const nextcloudUser = 'admin';
const auth = Buffer.from(`${nextcloudUser}:4EMsB-kQLNn-YdnCC-9Dd6Z-GA9jj`).toString('base64');
const eventUrl = `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}/${eventId}.ics`;

try {
  const response = await fetch(eventUrl, { method: 'PUT', headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'text/calendar' }, body: lines.join('\r\n') });
  return [{ json: { success: response.ok, message: response.ok ? 'Event created!' : 'Failed', event: { title: body.title, start: body.start, end: body.end, uid: `n8n-event-${eventId}` } } }];
} catch (error) { return [{ json: { success: false, error: error.message } }]; }

const body = $('Set Config').first().json.body;
if (!body.eventUid) return [{ json: { success: false, message: 'eventUid required' } }];
const calendarName = body.calendar || 'personal';
const nextcloudUrl = 'https://cloud.tal.ahmed-rezk.com';
const nextcloudUser = 'admin';
const auth = Buffer.from(`${nextcloudUser}:4EMsB-kQLNn-YdnCC-9Dd6Z-GA9jj`).toString('base64');

const formatICalDate = (d) => { const pad = (n) => String(n).padStart(2,'0'); return `${d.getUTCFullYear()}${pad(d.getUTCMonth()+1)}${pad(d.getUTCDate())}T${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}${pad(d.getUTCSeconds())}Z`; };
const parseDate = (s) => { if (!s) return null; const d = new Date(s); return isNaN(d.getTime()) ? null : d; };
const now = new Date();
const startDate = parseDate(body.start);
const endDate = parseDate(body.end);
const sequence = (body.sequence || 0) + 1;

const lines = ['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//n8n//Nextcloud//EN','CALSCALE:GREGORIAN','BEGIN:VEVENT',`UID:${body.eventUid}`,`DTSTAMP:${formatICalDate(now)}`];
if (body.title !== undefined) lines.push(`SUMMARY:${body.title}`);
if (startDate) lines.push(`DTSTART:${formatICalDate(startDate)}`);
if (endDate) lines.push(`DTEND:${formatICalDate(endDate)}`);
if (body.description !== undefined) lines.push(`DESCRIPTION:${body.description}`);
if (body.location !== undefined) lines.push(`LOCATION:${body.location}`);
if (body.status) { const m = {'tentative':'TENTATIVE','confirmed':'CONFIRMED','cancelled':'CANCELLED'}; lines.push(`STATUS:${m[body.status]||body.status}`); }
if (body.categories) lines.push(`CATEGORIES:${Array.isArray(body.categories)?body.categories.join(','):body.categories}`);
lines.push(`SEQUENCE:${sequence}`,'END:VEVENT','END:VCALENDAR');

const eventUrl = `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}/${body.eventUid}.ics`;
try {
  const response = await fetch(eventUrl, { method: 'PUT', headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'text/calendar' }, body: lines.join('\r\n') });
  return [{ json: { success: response.ok, message: response.ok ? 'Event updated!' : 'Failed', event: { uid: body.eventUid, title: body.title, sequence } } }];
} catch (error) { return [{ json: { success: false, error: error.message } }]; }

const body = $('Set Config').first().json.body;
if (!body.eventUid) return [{ json: { success: false, message: 'eventUid required' } }];
const calendarName = body.calendar || 'personal';
const nextcloudUrl = 'https://cloud.tal.ahmed-rezk.com';
const nextcloudUser = 'admin';
const auth = Buffer.from(`${nextcloudUser}:4EMsB-kQLNn-YdnCC-9Dd6Z-GA9jj`).toString('base64');
const eventUrl = `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}/${body.eventUid}.ics`;

try {
  const response = await fetch(eventUrl, { method: 'DELETE', headers: { 'Authorization': `Basic ${auth}` } });
  return [{ json: { success: response.ok || response.status === 204, message: 'Event deleted!', eventUid: body.eventUid } }];
} catch (error) { return [{ json: { success: false, error: error.message } }]; }
